mapper.select:
SELECT * FROM sys_operate_log ol

    ol.deleted = 0

        AND ol.title LIKE CONCAT('%', #{title}, '%')


        AND ol.operator_name LIKE CONCAT('%', #{operatorName}, '%')


        AND ol.business_type = #{businessType}


        AND ol.status = #{status}


        AND ol.operate_time >= #{startTime}


        AND ol.operate_time <= #{endTime}


ORDER BY ol.operate_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM sys_operate_log ol

    ol.deleted = 0

        AND ol.title LIKE CONCAT('%', #{title}, '%')


        AND ol.operator_name LIKE CONCAT('%', #{operatorName}, '%')


        AND ol.business_type = #{businessType}


        AND ol.status = #{status}


        AND ol.operate_time >= #{startTime}


        AND ol.operate_time <= #{endTime}


ORDER BY ol.operate_time DESC

SELECT COUNT(*) FROM sys_operate_log ol

    ol.deleted = 0

        AND ol.title LIKE CONCAT('%', #{title}, '%')


        AND ol.operator_name LIKE CONCAT('%', #{operatorName}, '%')


        AND ol.business_type = #{businessType}


        AND ol.status = #{status}


        AND ol.operate_time >= #{startTime}


        AND ol.operate_time <= #{endTime}

SELECT DATE (operate_time) as date, COUNT (*) as count
FROM sys_operate_log
WHERE operate_time >= #{startTime}
  AND operate_time <= #{endTime}
GROUP BY DATE (operate_time)
ORDER BY date

SELECT title as module, COUNT(*) as count
FROM sys_operate_log
WHERE operate_time >= #{startTime}
  AND operate_time <= #{endTime}
GROUP BY title
ORDER BY count DESC

SELECT SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as success,
       SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) as fail,
       COUNT(*)                                    as total
FROM sys_operate_log
WHERE operate_time >= #{startTime}
  AND operate_time <= #{endTime}

SELECT HOUR (operate_time) as hour, COUNT (*) as count
FROM sys_operate_log
WHERE operate_time >= #{startTime}
  AND operate_time <= #{endTime}
GROUP BY HOUR (operate_time)
ORDER BY hour

SELECT operator_name as username, COUNT(*) as count
FROM sys_operate_log
WHERE operate_time >= #{startTime}
  AND operate_time <= #{endTime}
  AND operator_name IS NOT NULL
  AND operator_name != ''
GROUP BY operator_name
ORDER BY count DESC
    LIMIT #{limit}
